import{_ as t,o,c as s,a0 as i}from"./chunks/framework.C6nzqSM0.js";const u=JSON.parse('{"title":"Permissions — opening scopes in the Feishu app backend","description":"","frontmatter":{},"headers":[],"relativePath":"en/reference/permissions.md","filePath":"en/reference/permissions.md","lastUpdated":1781385680000}'),a={name:"en/reference/permissions.md"};function d(n,e,r,c,l,p){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="permissions-—-opening-scopes-in-the-feishu-app-backend" tabindex="-1">Permissions — opening scopes in the Feishu app backend <a class="header-anchor" href="#permissions-—-opening-scopes-in-the-feishu-app-backend" aria-label="Permalink to &quot;Permissions — opening scopes in the Feishu app backend&quot;">​</a></h1><blockquote><p><strong>Every Feishu/Lark bot needs scopes opened in the app backend before it can read messages, send replies, or interact with Feishu Docs</strong>. This page is the canonical checklist of which scopes to open for which capabilities, and the per-OS path to verify they were opened.</p></blockquote><h2 id="per-capability-scope-list" tabindex="-1">Per-capability scope list <a class="header-anchor" href="#per-capability-scope-list" aria-label="Permalink to &quot;Per-capability scope list&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Required scope (Chinese)</th><th>Required scope (English)</th><th>Why needed</th></tr></thead><tbody><tr><td><strong>Receive DM</strong></td><td><code>im:message</code></td><td><code>im:message</code></td><td>Subscribe to <code>im.message.receive_v1</code> events</td></tr><tr><td><strong>Receive @bot in group</strong></td><td><code>im:message.group_at_msg</code> (or <code>im:message</code> for all group messages)</td><td><code>im:message.group_at_msg</code></td><td>Only messages @bot or all (per app config)</td></tr><tr><td><strong>Send DM / group message</strong></td><td><code>im:message.send_as_bot</code></td><td><code>im:message.send_as_bot</code></td><td>POST to <code>/im/v1/messages</code></td></tr><tr><td><strong>Read user open_id</strong></td><td><code>contact:user.id:readonly</code></td><td><code>contact:user.id:readonly</code></td><td><code>sender.sender_id.open_id</code> lookup</td></tr><tr><td><strong>Upload / send image</strong></td><td><code>im:resource</code></td><td><code>im:resource</code></td><td>image messages via <code>/im/v1/images</code></td></tr><tr><td><strong>Upload / send file</strong></td><td><code>im:resource</code></td><td><code>im:resource</code></td><td>file messages via <code>/im/v1/files</code></td></tr><tr><td><strong>Read Feishu Docs</strong></td><td><code>docx:document:readonly</code></td><td><code>docx:document:readonly</code></td><td>fetch doc content via <code>/docx/v1/documents/:id/raw_content</code></td></tr><tr><td><strong>Edit Feishu Docs</strong></td><td><code>docx:document</code></td><td><code>docx:document</code></td><td>edit doc content via <code>/docx/v1/documents/:id/...</code></td></tr><tr><td><strong>Create Feishu Docs</strong></td><td><code>docx:document:create</code></td><td><code>docx:document:create</code></td><td>POST <code>/docx/v1/documents</code></td></tr><tr><td><strong>Search Feishu Wiki / Docs</strong></td><td><code>wiki:wiki:readonly</code></td><td><code>wiki:wiki:readonly</code></td><td>search via <code>/wiki/v1/spaces/.../nodes/search</code></td></tr><tr><td><strong>Read user email (rarely needed)</strong></td><td><code>contact:user.email:readonly</code></td><td><code>contact:user.email:readonly</code></td><td>only if your bot sends email notifications</td></tr></tbody></table><p><strong>Per the owner definition</strong> (hermes/larkbot requires <strong>all 3</strong> top-level capabilities):</p><ol><li><strong>DM</strong> (私聊)</li><li><strong>Group chat</strong> (群聊)</li><li><strong>Feishu Docs</strong> (飞书文档)</li></ol><p>→ open scopes for all three blocks above.</p><h2 id="per-os-verification-path" tabindex="-1">Per-OS verification path <a class="header-anchor" href="#per-os-verification-path" aria-label="Permalink to &quot;Per-OS verification path&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>Open <code>https://open.feishu.cn/app</code> in Safari</li><li>Click your app → &quot;权限管理&quot; (Permissions)</li><li>Verify the 3 blocks above are checked</li><li>Also click &quot;事件订阅&quot; (Event Subscription): <ul><li>Add &quot;接收消息 im.message.receive_v1&quot; (Receive messages v1)</li><li>Verification Token / Encrypt Key — copy these, paste into your <code>credentials.json</code> (only for Webhook mode; WS mode doesn&#39;t need these)</li></ul></li><li>From a terminal, verify the bot process can read them:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  {&quot;app_id&quot;: &quot;cli_xxx&quot;, &quot;app_secret&quot;: &quot;yyy&quot;}</span></span></code></pre></div></li></ol><h3 id="windows-wsl2" tabindex="-1">Windows (WSL2) <a class="header-anchor" href="#windows-wsl2" aria-label="Permalink to &quot;Windows (WSL2)&quot;">​</a></h3><p>Same as macOS but from inside WSL2:</p><ol><li><code>wsl</code> to enter Ubuntu</li><li><code>xdg-open https://open.feishu.cn/app</code> (or copy URL to Windows browser)</li><li>Follow macOS steps 2-5</li></ol><h3 id="linux-no-gui" tabindex="-1">Linux (no GUI) <a class="header-anchor" href="#linux-no-gui" aria-label="Permalink to &quot;Linux (no GUI)&quot;">​</a></h3><ol><li>On another machine, open <code>https://open.feishu.cn/app</code> in a browser</li><li>Apply scopes, copy Encrypt Key / Verification Token</li><li>SSH / scp the credentials file:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># On your Linux box:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (paste the credentials JSON from clipboard)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{&quot;app_id&quot;: &quot;cli_xxx&quot;, &quot;app_secret&quot;: &quot;yyy&quot;}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span></span></code></pre></div></li></ol><h2 id="per-deployment-mode-token-management" tabindex="-1">Per-deployment-mode token management <a class="header-anchor" href="#per-deployment-mode-token-management" aria-label="Permalink to &quot;Per-deployment-mode token management&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Deployment</th><th>Token storage</th><th>Encrypted at rest?</th></tr></thead><tbody><tr><td>macOS (this repo)</td><td><code>~/Library/Application Support/lark-cli/master.key.file</code> + <code>appsecret_cli_&lt;appid&gt;.enc</code></td><td>✅ lark-cli AES-256-GCM</td></tr><tr><td>macOS (alt)</td><td><code>~/.config/feishu/credentials.json</code> (plaintext)</td><td>❌ (chmod 600)</td></tr><tr><td>Windows</td><td><code>%APPDATA%\\lark-cli\\...</code> or <code>~/.config/feishu/credentials.json</code></td><td>depends</td></tr><tr><td>Linux</td><td><code>~/.config/feishu/credentials.json</code> (plaintext) or systemd credential store</td><td>❌ or ✓</td></tr></tbody></table><p><strong>Recommendation</strong>: use the lark-cli-encrypted form when available (macOS this repo does), plaintext + <code>chmod 600</code> is the fallback.</p><h2 id="权限被回收-permission-revoked-symptoms" tabindex="-1">&quot;权限被回收&quot; (permission revoked) symptoms <a class="header-anchor" href="#权限被回收-permission-revoked-symptoms" aria-label="Permalink to &quot;&quot;权限被回收&quot; (permission revoked) symptoms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td>ws connection dies after 1-2 messages, log shows &quot;permission denied&quot;</td><td>Feishu admin removed a scope</td><td>re-open in app backend; restart bot daemon</td></tr><tr><td>Send API returns <code>99991663</code> (no scope)</td><td>Your code calls a scope not opened</td><td>add the scope; wait 1-2 minutes for Feishu cache</td></tr><tr><td>Receive API works but <code>sender</code> field is empty</td><td>Missing <code>contact:user.id:readonly</code></td><td>add the scope</td></tr><tr><td><code>reply</code> POST returns 404 (chat not found)</td><td>Bot is not in that chat (group)</td><td>invite bot to the group first</td></tr></tbody></table><h2 id="cross-os-note-re-open-scopes-in-1-place-propagate" tabindex="-1">Cross-OS note: re-open scopes in 1 place, propagate <a class="header-anchor" href="#cross-os-note-re-open-scopes-in-1-place-propagate" aria-label="Permalink to &quot;Cross-OS note: re-open scopes in 1 place, propagate&quot;">​</a></h2><p>When you re-open a scope in the Feishu app backend:</p><ul><li>The change propagates to all clients (WS, Webhook) within 1-2 minutes</li><li>The bot daemon does <strong>NOT</strong> need to be restarted</li><li>BUT: the Feishu SDK may cache the scope list at connection time; if you open a scope while the bot is running, the bot may need to reconnect (i.e. kill + restart)</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../guides/connection-modes">Connection modes</a> — WS vs Webhook</li><li><a href="./../guides/ai-tools-hermes">Hermes integration</a></li><li><a href="./../protocol/feishu-inbox-protocol">inbox/outbox protocol</a></li></ul>`,25)])])}const m=t(a,[["render",d]]);export{u as __pageData,m as default};
